{
  "audit_scope": {
    "task": "L2-008",
    "audit_object": "以R004212为线索的拆分报销异常",
    "period": "2025-04-03至2025-04-17（R004212费用日期前后7天）",
    "organization": "财务管理部(D009)",
    "employee": "E0009 张婷",
    "expense_type": "travel_lodging"
  },
  "verified_facts": [
    "R004212：员工E0009（张婷，D1/部门经理），差旅住宿费，2025-04-10，¥5,100.00，7晚，一类城市，发票FP2025X0004206，审批档位AR-02（部门经理+财务复核），无特殊审批",
    "R004213：同一员工E0009，差旅住宿费，2025-04-15，¥5,100.00，7晚，一类城市，发票FP2025X0004207，审批档位AR-02（部门经理+财务复核），无特殊审批",
    "两笔费用间隔5天，在7天窗口内（2025-04-10至2025-04-15）",
    "两笔费用合计¥10,200.00",
    "单笔¥5,100属于AR-02档（≥¥3,000且<¥10,000）；合计¥10,200属于AR-03档（≥¥10,000且<¥50,000），审批角色从「部门经理+财务复核」跃升至「部门总经理」",
    "两笔均未取得特殊审批"
  ],
  "applicable_policies": [
    {"doc_id": "01_expense_reimbursement_2025.md", "clause_no": "第十一条", "content": "不得将同一事项或同类事项拆分为多笔报销以规避审批权限。同一员工、同一费用类型在7天内出现2笔及以上报销，且合计金额达到《授权管理办法》附件二较高审批线的，应重点核查拆分规避审批。"},
    {"doc_id": "03_authorization_management.md", "clause_no": "附件二", "content": "AR-02: ≥¥3,000且<¥10,000→部门经理+财务复核; AR-03: ≥¥10,000且<¥50,000→部门总经理"}
  ],
  "findings": [
    {
      "anomaly_id": "SPLIT-001",
      "description": "员工E0009于2025-04-10和2025-04-15分别提交两笔均为¥5,100的差旅住宿报销（R004212、R004213），单笔均落在AR-02审批档位（部门经理+财务复核），但合计¥10,200达到AR-03档位（部门总经理），构成规避审批权限的拆分报销行为。",
      "record_ids": ["R004212", "R004213"],
      "impact": "规避部门总经理审批，两笔费用仅经部门经理+财务复核即获批准，未触发应适用的更高审批层级。"
    }
  ],
  "recommendations": [
    "将R004212和R004213合并视同一笔¥10,200的费用，补充部门总经理审批",
    "在费用系统中加强同一员工同类型费用7天窗口内的合计监控与预警"
  ],
  "anomaly_ids": ["SPLIT-001"],
  "record_ids": ["R004212", "R004213"],
  "citations": [
    {"doc_id": "01_expense_reimbursement_2025.md", "clause_no": "第十一条"},
    {"doc_id": "03_authorization_management.md", "clause_no": "附件二"}
  ],
  "answer": "经核查，以R004212为线索，发现员工E0009（张婷）存在拆分报销异常：R004212（2025-04-10，¥5,100）与R004213（2025-04-15，¥5,100）同为差旅住宿费，两笔费用间隔5天（在7天窗口内），合计¥10,200达到授权管理办法附件二AR-03档位（≥¥10,000需部门总经理审批），但两笔均仅经AR-02档位（部门经理+财务复核）审批通过，构成规避审批权限的拆分报销行为，违反《XX证券费用报销管理办法(2025修订版)》第十一条。",
  "limitations": []
}

